insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:6-3-globalisation:mcq:c6f7bbea', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "International branding requires businesses to ''think global, act local''. What does this mean?", "options": ["Translate all advertising into every language", "Sell the same product at the same price globally", "Maintain core brand values worldwide but adapt the message for local cultures", "Only promote products in countries where average incomes are high"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. ''Think global, act local'' means a business maintains a consistent global brand identity (e.g. logo, core values) while adapting elements like language, imagery and promotions to suit local cultural and religious norms."}'::jsonb),
('business:6-3-globalisation:mcq:e2b0394d', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit of becoming a multinational for the host country?", "options": ["Profits are kept in the host country", "Local firms always grow stronger due to increased competition", "Jobs and tax revenues are created in the host country", "The host country''s currency always strengthens"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. MNCs bring jobs to host countries, increasing incomes and local spending. They also pay taxes which fund public services. However, profits are often repatriated to the home country."}'::jsonb),
('business:6-3-globalisation:mcq:908e8944', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Raleigh Cycles moved production to Taiwan. Which factor best explains this decision?", "options": ["Proximity to major UK customers", "Lower labour and production costs abroad", "Better quality control near UK headquarters", "To avoid paying UK corporation tax"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Raleigh moved production to Taiwan primarily to reduce costs — wages and manufacturing costs were significantly lower there than in the UK, improving competitiveness."}'::jsonb),
('business:6-3-globalisation:mcq:80a8cfa6', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "What is free trade?", "options": ["Trade between businesses that do not charge customers", "The absence of barriers such as tariffs or quotas between countries", "A government scheme that subsidises domestic exporters", "Trade only conducted between countries with the same currency"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Free trade means trading between countries without barriers like tariffs, quotas or regulations. It is encouraged by organisations like the WTO and exists in areas like NAFTA and SAFTA."}'::jsonb),
('business:6-3-globalisation:mcq:368e9f9d', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of globalisation for a host country?", "options": ["Access to foreign investment and technology", "New job opportunities for local workers", "Profits sent back to the MNC''s home country, reducing local economic benefit", "Lower prices for consumers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A key drawback of MNCs in host countries is profit repatriation — where profits are transferred to the company''s home country headquarters rather than being reinvested locally, limiting economic benefit."}'::jsonb),
('business:6-3-globalisation:tf:e2319576', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "A tariff is a limit on the quantity of a good that can be imported."}'::jsonb, '{"answer": false, "explain": "FALSE. A tariff is a TAX on imported goods. A QUOTA is the limit on the quantity or value of imports. These are two different trade barriers."}'::jsonb),
('business:6-3-globalisation:tf:bcea65ab', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "A multinational company is defined as any business that sells products to customers in another country."}'::jsonb, '{"answer": false, "explain": "FALSE. A multinational company must OPERATE in more than one country — meaning it has physical facilities such as factories, offices or staff there. Simply selling abroad does not make a business multinational."}'::jsonb),
('business:6-3-globalisation:tf:87b4227e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "When the pound strengthens against other currencies, UK exports become more expensive for foreign buyers."}'::jsonb, '{"answer": true, "explain": "TRUE. A stronger pound means foreign buyers need more of their currency to buy the same amount of pounds. This makes UK goods more expensive abroad, potentially reducing export sales — as summarised by SPICED."}'::jsonb),
('business:6-3-globalisation:tf:b12d2387', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Free trade means there are no tariffs, quotas, or restrictions on trade between countries."}'::jsonb, '{"answer": true, "explain": "TRUE. Free trade is defined as the absence of barriers (tariffs, quotas, regulations) on international trade. Examples of free trade areas include NAFTA and SAFTA."}'::jsonb),
('business:6-3-globalisation:tf:7f2bb12e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "International branding means a business sells its products in every country in the world."}'::jsonb, '{"answer": false, "explain": "FALSE. International branding means creating a brand image that is recognised and promoted across multiple countries — but a business does not need to sell everywhere to have an international brand."}'::jsonb),
('business:6-3-globalisation:tf:185bb6e6', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "One benefit for a host country when an MNC locates there is that jobs and tax revenues are created."}'::jsonb, '{"answer": true, "explain": "TRUE. MNCs create employment for local workers and pay taxes to the host government, helping to fund public services such as schools and hospitals."}'::jsonb),
('business:6-3-globalisation:tf:83c48f7a', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "When the pound weakens, UK imports become cheaper for domestic businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. When the pound weakens, imports become MORE expensive because it costs more pounds to buy the same amount of foreign currency. A weaker pound makes exports cheaper, not imports."}'::jsonb),
('business:6-3-globalisation:tf:1fa2e83c', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Containerisation has helped reduce the cost of international trade by standardising how goods are transported by sea."}'::jsonb, '{"answer": true, "explain": "TRUE. Standardised shipping containers can be loaded quickly between ships, lorries, and trains, dramatically cutting transport costs and boosting global trade volumes."}'::jsonb),
('business:6-3-globalisation:tf:7cb4fdab', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Raleigh Cycles moved production back to the UK to take advantage of lower labour costs."}'::jsonb, '{"answer": false, "explain": "FALSE. Raleigh moved production TO Taiwan (abroad) to benefit from lower labour costs. Some production was later returned to the UK, but the initial move abroad was specifically to cut costs."}'::jsonb),
('business:6-3-globalisation:tf:4a425dc9', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "One risk of a multinational becoming too large is that it may face diseconomies of scale, becoming harder to manage efficiently."}'::jsonb, '{"answer": true, "explain": "TRUE. As MNCs grow very large and spread across many countries, coordination becomes complex, communication slows down, and management costs rise — all signs of diseconomies of scale."}'::jsonb),
('business:6-3-globalisation:tf:bb643768', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "After Brexit, UK businesses can now export to the EU with no additional paperwork or checks."}'::jsonb, '{"answer": false, "explain": "FALSE. Since January 2021, UK exports to the EU require additional documentation, health certificates, and border checks. Some businesses have had to stop exporting to the EU entirely due to these increased costs."}'::jsonb),
('business:6-3-globalisation:tf:8e99ee31', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "The principle ''think global, act local'' means a business should sell identical products in every country without any adaptations."}'::jsonb, '{"answer": false, "explain": "FALSE. ''Think global, act local'' means maintaining a consistent global brand identity while ADAPTING the message, products, or promotions to suit local cultures, religions, and income levels in each market."}'::jsonb),
('business:6-3-globalisation:learn:cd293821', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "What is Globalisation?", "reading": "<p><strong>Globalisation</strong> is the process by which business activity around the world has become increasingly interconnected. It involves three key movements:</p>\n<ul>\n<li><strong>Trade:</strong> Buying and selling goods and services made in different countries.</li>\n<li><strong>People:</strong> The movement of workers from country to country.</li>\n<li><strong>Capital:</strong> The movement of money or assets (machines, buildings, vehicles) from country to country.</li>\n</ul>\n<p>Globalisation has increased at a rapid rate, driven by three major improvements:</p>\n<ul>\n<li><strong>Transport:</strong> Costs have fallen as ships and planes have grown bigger. The development of <strong>containers</strong> — standardised boxes lifted by crane from ship to lorry — has significantly reduced costs.</li>\n<li><strong>Telecommunications & the Internet:</strong> Communication is faster and cheaper. Businesses can research suppliers worldwide, order via email or video-conferencing, and promote products through websites and social media.</li>\n<li><strong>Free Trade Arrangements:</strong> <strong>Free trade</strong> exists when there are no barriers such as <strong>tariffs</strong> (taxes on imports), <strong>quotas</strong> (limits on the amount imported) or <strong>regulations</strong> (rules on goods that can be sold). The WTO encourages countries to remove these barriers. Examples of free trade areas include NAFTA (USA, Canada, Mexico) and SAFTA (South Asia).</li>\n</ul>", "question": "According to this card, what are the three key movements involved in globalisation?", "options": ["Trade, people, and capital movement", "Tariffs, quotas, and regulations", "Imports, exports, and exchange rates", "Branding, marketing, and advertising"]}'::jsonb, '{"answer": 0, "explain": "The card explains globalisation involves three key movements: trade (goods/services), people (workers), and capital (money and assets) between countries."}'::jsonb),
('business:6-3-globalisation:learn:ff63e0a9', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Key Terminology", "reading": "<ul>\n<li><strong>Globalisation:</strong> The process by which business activity around the world has become increasingly interconnected.</li>\n<li><strong>International Branding:</strong> Creating an image or values for a product that are communicated in countries around the world.</li>\n<li><strong>Free Trade:</strong> The absence of restrictions on trade between countries.</li>\n<li><strong>Tariff:</strong> A tax on a good or service that is imported.</li>\n<li><strong>Quota:</strong> A limit in terms of weight or value on the amount of a good or service that can be imported.</li>\n<li><strong>Regulations:</strong> Rules about the goods and services that can be sold in a country.</li>\n<li><strong>Multinational Company (MNC):</strong> A business that operates in different countries around the world.</li>\n<li><strong>Productivity:</strong> A measure of the output of each worker on average.</li>\n<li><strong>Unit Cost:</strong> The cost per unit produced. The greater the productivity of workers, the lower the unit cost.</li>\n<li><strong>Exchange Rate:</strong> The price of one currency in terms of another (e.g. £1 = €1.2).</li>\n</ul>", "question": "According to the key terminology, what is a ''quota''?", "options": ["A tax charged on a good or service that is imported", "A limit on the weight or value of a good that can be imported", "A rule about the goods and services that can be sold in a country", "The price of one currency expressed in terms of another"]}'::jsonb, '{"answer": 1, "explain": "The card defines a quota as a limit on the weight or value of a good that can be imported — distinct from a tariff (a tax) or a regulation (a rule)."}'::jsonb),
('business:6-3-globalisation:learn:f11e74ee', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Multinational Companies (MNCs)", "reading": "<p><strong>Multinational companies (MNCs)</strong> are businesses that operate in more than one country. They are a key feature of globalisation. Well-known examples include Google, Amazon, Coca-Cola, Starbucks and McDonald''s.</p>\n<p>There are several advantages to a <strong>business</strong> of becoming a multinational:</p>\n<ul>\n<li><strong>Increasing sales:</strong> Selling in more countries increases the size of the market and potential revenue.</li>\n<li><strong>Spreading risk:</strong> If one market suffers a recession, the company can compensate with sales growth in another country.</li>\n<li><strong>Lower costs:</strong> Production may be cheaper in another country due to lower wages, cheaper land, or better technology.</li>\n<li><strong>Tax avoidance:</strong> MNCs may set up headquarters in low-tax countries (e.g. Luxembourg or Ireland) to reduce their overall tax bill, even while selling in higher-tax countries.</li>\n</ul>", "question": "According to this card, why might a business become a multinational to reduce risk?", "options": ["Multinationals are legally protected from ever making a loss at all", "Multinationals never have to pay any tax in any country they operate in", "If one market suffers a recession, sales growth elsewhere can compensate", "Multinationals only ever sell their products in a single country at once"]}'::jsonb, '{"answer": 2, "explain": "The card lists spreading risk as an advantage of becoming multinational — if one market suffers a recession, growth in another market can compensate."}'::jsonb),
('business:6-3-globalisation:learn:2b3c463f', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Impact of MNCs on the Host Country", "reading": "<p>The country where a multinational locates is called the <strong>host country</strong>. MNCs bring both benefits and drawbacks to that country.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages to Host Country</div>\n<div class=\"pro-item\"><strong>Creates demand for local businesses:</strong> MNCs employ local people, increasing incomes and local spending. They may also buy supplies from local firms.</div>\n<div class=\"pro-item\"><strong>Taxes & public services:</strong> Tax payments by MNCs help governments fund education, health and infrastructure.</div>\n<div class=\"pro-item\"><strong>Lower prices:</strong> By keeping costs low, MNCs may offer goods and services at cheaper prices for consumers and businesses.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages to Host Country</div>\n<div class=\"con-item\"><strong>Business closures:</strong> Local firms may be unable to compete on price or quality and get forced out of business. MNCs may also pay higher wages, pulling workers away from local employers.</div>\n<div class=\"con-item\"><strong>Outflows of money:</strong> Profits are often sent back to the MNC''s home country headquarters, limiting the financial benefit to the host country.</div>\n<div class=\"con-item\"><strong>Diseconomies of scale:</strong> As MNCs grow very large, they can become harder to manage and less efficient.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Vodafone in the UK</h4>\n<p>Vodafone sells mobile and ICT services across many countries. Although headquartered in the UK, profits are routed to Luxembourg where taxation is much lower — a practice accused of being tax avoidance. Vodafone disputes this, arguing it pays all taxes legally owed and contributes through investment, job creation and over £1.2 billion spent on UK network upgrades. This case illustrates the debate around whether MNCs truly benefit host countries or exploit lower-tax loopholes.</p>\n</div>", "question": "According to the Vodafone case study, what practice is Vodafone accused of?", "options": ["Refusing to invest any money at all in UK network upgrades", "Selling all of its UK operations to a foreign competitor firm", "Employing no staff whatsoever within the United Kingdom itself", "Routing profits to Luxembourg, where taxation is much lower"]}'::jsonb, '{"answer": 3, "explain": "The card explains Vodafone routes profits to Luxembourg where taxation is lower — a practice accused of being tax avoidance, which Vodafone disputes."}'::jsonb),
('business:6-3-globalisation:learn:8f54dd36', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Influences on Business Location", "reading": "<p>Globalisation means businesses have greater freedom to choose <strong>where</strong> they locate production. A UK business may move production abroad — or bring it back home — for several reasons.</p>\n<p><strong>Reasons to locate ABROAD:</strong></p>\n<ul>\n<li><strong>Lower labour costs:</strong> Wages are much lower in many countries, especially in the Far East. This is why Raleigh Cycles moved production to Taiwan.</li>\n<li><strong>Lower technology costs:</strong> Some foreign firms have invested more in up-to-date manufacturing technology, reducing production costs.</li>\n<li><strong>Lower property/land costs:</strong> Factories and premises may be cheaper abroad.</li>\n<li><strong>Access to expertise:</strong> Businesses may locate near specialist skills or R&D talent in other countries.</li>\n<li><strong>Proximity to demand:</strong> Locating near the target market can increase sales. The Electric Car Corporation moved production to Denmark because demand for electric cars was stronger there.</li>\n</ul>\n<p><strong>Reasons to move production BACK to the UK:</strong></p>\n<ul>\n<li><strong>Quality control:</strong> It is easier to monitor standards when production is close to headquarters.</li>\n<li><strong>Communications:</strong> No language barriers or time zone differences with a UK workforce.</li>\n<li><strong>Skilled labour:</strong> The UK has a strong supply of skilled workers in many industries.</li>\n<li><strong>Consumer preference:</strong> Many UK customers prefer goods labelled ''Made in Britain''.</li>\n<li><strong>Environment:</strong> UK production reduces transport distances, lowering the business''s carbon footprint — a strong marketing point.</li>\n<li><strong>Rising foreign wages:</strong> As wages in developing countries increase, the cost advantage of producing abroad shrinks.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: Raleigh Cycles</h4>\n<p>Raleigh, the famous Nottingham bicycle manufacturer, went bankrupt in the 2000s. New owners moved production to Taiwan and South East Asia to cut costs, while keeping sales, marketing and design in the UK. The business recovered strongly and has since moved some assembly back to Nottingham — showing that location decisions are not permanent and must be regularly reviewed.</p>\n</div>", "question": "According to the Raleigh Cycles case study, what does the company''s history show?", "options": ["Location decisions are not permanent and must be regularly reviewed", "Once a business moves abroad, it can never return production home", "Raleigh has never produced any bicycles outside of Nottingham at all", "Moving production abroad always causes a company to go bankrupt"]}'::jsonb, '{"answer": 0, "explain": "The card explains Raleigh moved production to Taiwan then moved some assembly back to Nottingham — showing location decisions must be regularly reviewed."}'::jsonb),
('business:6-3-globalisation:learn:040aa3c1', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "International Branding", "reading": "<p><strong>Branding</strong> refers to a product''s image, reputation and values — communicated through logos, words, images, music and media (TV, social media, websites). When selling globally, a business must adapt its branding to suit each country. The key principle is: <strong>\"Think global, act local\"</strong> — promote the same core values worldwide, but deliver the message differently in each market.</p>\n<p>Businesses must consider the following factors when creating an international brand:</p>\n<ul>\n<li><strong>Culture & Religion:</strong> Images or themes acceptable in one country may deeply offend in another. A Coca-Cola ad featuring Father Christmas would not work in a predominantly Muslim country like Pakistan.</li>\n<li><strong>Language:</strong> Product names, slogans and advertisements must be translated carefully. An American fast food company mistakenly advertised ''yassuppoi'' chips in Japan — meaning ''low quality'' in Japanese.</li>\n<li><strong>Names:</strong> Products sometimes need different names. Burger King operates as ''Hungry Jack''s'' in Australia because the Burger King name was already trademarked there.</li>\n<li><strong>Level & Distribution of Income:</strong> There is no point promoting a luxury product in a country where most people cannot afford it. Businesses must research average incomes and how evenly wealth is spread.</li>\n<li><strong>Legal Factors:</strong> Businesses must follow local advertising laws. Alcohol advertising is illegal in Sri Lanka; cigarettes are banned entirely in Bhutan.</li>\n<li><strong>Bribery:</strong> In some countries, bribery is commonplace in business dealings. In the UK it is illegal and carries serious reputational and legal consequences.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: McDonald''s in India</h4>\n<p>McDonald''s adapts its products to suit local cultures. In India, where beef is not eaten for religious reasons, the Big Mac is made from chicken and marketed as the ''Maharajah Mac'' (meaning king-size burger). Prices are also lower — around £1.97 compared to £3.25 in the UK — to reflect lower average incomes. This shows how the 4 Ps (Product, Price, Promotion, Place) must all be adapted for international markets.</p>\n</div>", "question": "According to the McDonald''s in India case study, how did McDonald''s adapt its product?", "options": ["It refused to sell any burgers at all within the Indian market", "It made the Big Mac from chicken instead of beef, for religious reasons", "It charged higher prices in India than in the UK for the same burger", "It kept the exact same product and price as in every other country"]}'::jsonb, '{"answer": 1, "explain": "The card explains McDonald''s made the ''Maharajah Mac'' from chicken (since beef is not eaten for religious reasons in India) and priced it lower than the UK Big Mac."}'::jsonb),
('business:6-3-globalisation:learn:befecff2', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "How Businesses Compete Internationally", "reading": "<p>Competing internationally means both selling abroad and competing against foreign firms at home. Businesses must adapt across all areas of the organisation:</p>\n<ul>\n<li><strong>Growth:</strong> Businesses may expand organically (e.g. Marks & Spencer opening shops across the world) or through joint ventures (e.g. Jaguar Land Rover partnering with Chery in China to produce and sell cars without import tariffs).</li>\n<li><strong>Marketing (4 Ps):</strong> Products may need to be changed (e.g. JLR makes longer wheelbase cars for Chinese buyers); prices adjusted for local incomes; promotions must reflect local culture; and place decisions must consider whether to be near customers or raw materials.</li>\n<li><strong>Human Resources:</strong> Businesses must recruit and train overseas workers, comply with local employment laws, and find suitable ways to motivate staff in different cultural contexts.</li>\n<li><strong>Business Operations:</strong> Methods of production may need to change — switching from job to batch production to cut costs. Quality assurance processes must be put in place if producing abroad.</li>\n<li><strong>Finance:</strong> International expansion requires sources of finance for investment. Break-even analysis helps businesses assess whether selling in a new country will be profitable.</li>\n<li><strong>Ethical & Environmental:</strong> Businesses must consider the ethical implications of producing in countries with weaker labour laws or environmental standards. Negative publicity (e.g. Primark and child labour accusations) can damage a brand significantly.</li>\n</ul>", "question": "According to this card, why did Jaguar Land Rover form a joint venture with Chery in China?", "options": ["To stop selling any of its cars within the United Kingdom market", "To avoid ever having to adapt its products for Chinese buyers", "To produce and sell cars in China without paying import tariffs", "To prevent Chinese customers from being able to buy its cars"]}'::jsonb, '{"answer": 2, "explain": "The card explains JLR partnered with Chery in China to produce and sell cars there without import tariffs, while also adapting products like longer wheelbase cars."}'::jsonb),
('business:6-3-globalisation:learn:39585cea', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Exchange Rates & International Competitiveness", "reading": "<p>The <strong>exchange rate</strong> is the price of one currency in terms of another (e.g. £1 = €1.20). Changes in the exchange rate directly affect the price of exports and imports, and therefore a business''s competitiveness abroad.</p>\n<p>A useful mnemonic to remember the effects is <strong>SPICED</strong>:</p>\n<div class=\"formula-box\">\n<strong>SPICED</strong> = Strong Pound → Imports Cheaper, Exports Dearer\n</div>\n<ul>\n<li><strong>If the pound rises (strengthens):</strong> Exports become more expensive for foreign buyers (likely to reduce export sales). Imports become cheaper for UK businesses (good for importers, but harder for domestic producers to compete).</li>\n<li><strong>If the pound falls (weakens):</strong> Exports become cheaper for foreign buyers (likely to increase export sales). Imports become more expensive (raises costs for UK firms that rely on imported materials).</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Weak Pound — Good For</div>\n<div class=\"pro-item\"><strong>Exporters:</strong> Their goods become cheaper abroad, increasing overseas sales. Brandauer, a Birmingham engineering firm, saw export sales rise after the pound fell following Brexit.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Weak Pound — Bad For</div>\n<div class=\"con-item\"><strong>Importers:</strong> Imported raw materials and components become more expensive, pushing up production costs. Princess Yachts noted costs rose as imported components became pricier after the pound fell.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Princess Yachts</h4>\n<p>Princess Yachts, based in Plymouth, sells 80% of its yachts abroad. After the pound fell in value, exports became cheaper for overseas buyers and sales increased. However, costs also rose slightly as some imported components became more expensive. This illustrates that exchange rate changes rarely have a simple, one-sided effect — businesses that both import and export must weigh up the overall impact carefully.</p>\n</div>", "question": "According to the SPICED mnemonic in this card, what happens when the pound is strong?", "options": ["Imports become dearer and exports become cheaper", "Both imports and exports become cheaper at the same time", "Both imports and exports become dearer at the same time", "Imports become cheaper and exports become dearer"]}'::jsonb, '{"answer": 3, "explain": "The SPICED mnemonic states: Strong Pound leads to Imports Cheaper, Exports Dearer — the reverse happens when the pound weakens."}'::jsonb),
('business:6-3-globalisation:learn:810f1640', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Brexit & Its Impact on UK Businesses", "reading": "<p>The UK officially left the European Union in January 2020. Since 1 January 2021, new trading rules have applied. Brexit has had both negative and positive effects on UK businesses.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✗ Negative Effects</div>\n<div class=\"con-item\"><strong>New paperwork & inspections:</strong> UK exports to the EU must now meet EU standards and be accompanied by documentation. This costs time and money, and border delays have slowed deliveries. Some UK firms have stopped trading with the EU entirely.</div>\n<div class=\"con-item\"><strong>Labour shortages:</strong> Freedom of movement has ended. EU workers must now apply for the right to work in the UK. Restaurant chains like D&D London (43 restaurants) have struggled to recruit skilled chefs as a result.</div>\n<div class=\"con-item\"><strong>Rules of origin:</strong> UK-made goods must use a minimum proportion of British components to qualify as ''Made in the UK'' when exporting to the EU.</div>\n<div class=\"con-item\"><strong>Northern Ireland complications:</strong> Goods moving from the rest of the UK to Northern Ireland are treated as exports to the EU, requiring extra checks.</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Positive Effects</div>\n<div class=\"pro-item\"><strong>New trade deals:</strong> The UK is now free to negotiate independently with non-EU countries. A deal with Japan already makes 99% of UK exports to Japan tariff-free.</div>\n<div class=\"pro-item\"><strong>Weaker pound boosts exports:</strong> The fall in the pound''s value after Brexit made UK exports cheaper. Brandauer (Birmingham) increased EU exports of precision-engineered components as a result.</div>\n<div class=\"pro-item\"><strong>Some inward investment:</strong> Nissan announced over £1 billion of investment to expand electric car production in Sunderland after the Brexit free-trade deal was secured.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: The Cheshire Cheese Company</h4>\n<p>Before Brexit, the Cheshire Cheese Company exported cheese to the EU with no tariffs and no additional paperwork. After Brexit, each export now requires a health certificate costing £180 — even for a gift package worth just £30. The owner estimated a loss of revenue of up to £250,000. This illustrates how non-tariff barriers (like certificates and inspections) can be just as damaging as tariffs for small exporters.</p>\n</div>", "question": "According to the Cheshire Cheese Company case study, what changed after Brexit?", "options": ["Each export now requires a health certificate costing £180", "Exports to the EU became completely free of any paperwork", "The company was banned from exporting any cheese at all", "Tariffs on cheese exports to the EU were removed entirely"]}'::jsonb, '{"answer": 0, "explain": "The card explains that after Brexit each export now requires a £180 health certificate, even for a small gift package — a non-tariff barrier that damaged the business."}'::jsonb),
('business:6-3-globalisation:misc:4f349608', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business that sells products to customers abroad is automatically a multinational company.</p><p><strong>✅ The correct idea:</strong> A multinational company must OPERATE in more than one country — having physical facilities, staff, or offices there. Simply exporting goods abroad does not make a business a multinational. The examiner''s report specifically warned against this confusion.</p>", "question": "Does selling products to customers abroad automatically make a business a multinational?", "options": ["Yes — any business that exports goods abroad is automatically a multinational", "No — a multinational must physically operate in more than one country", "Yes — but only if the business sells to more than ten different countries", "No — but only because multinationals are not allowed to export goods"]}'::jsonb, '{"answer": 1, "explain": "The card explains a multinational must OPERATE in more than one country with facilities or staff — simply exporting goods abroad does not make a business a multinational."}'::jsonb),
('business:6-3-globalisation:misc:7958aad7', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> International branding, international trade, and multinational company all mean the same thing.</p><p><strong>✅ The correct idea:</strong> These are three completely different concepts. International branding = creating a consistent brand image across countries. International trade = buying/selling across borders. Multinational company = physically operating in multiple countries. Confusing them will cost marks in every question.</p>", "question": "Are international branding, international trade, and multinational company the same concept?", "options": ["Yes — all three terms describe exactly the same business activity", "Yes — but only international trade and branding are the same thing", "No — they are three completely different business concepts entirely", "No — but only multinational and international trade mean the same thing"]}'::jsonb, '{"answer": 2, "explain": "The card explains these are three completely different concepts — branding is image, trade is buying/selling, and multinational means physically operating abroad."}'::jsonb),
('business:6-3-globalisation:misc:0aae806e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A tariff and a quota are the same type of trade barrier.</p><p><strong>✅ The correct idea:</strong> A tariff is a TAX on imported goods, making them more expensive. A quota is a LIMIT on the quantity or value of goods that can be imported. They are different tools with different mechanisms.</p>", "question": "What is the key difference between a tariff and a quota?", "options": ["A tariff and a quota are simply two different names for the same tool", "A quota is a tax on imports, while a tariff is a limit on import quantity", "A tariff only applies to exports, while a quota only applies to imports", "A tariff is a tax on imports, while a quota is a limit on import quantity"]}'::jsonb, '{"answer": 3, "explain": "The card explains a tariff is a TAX on imported goods, while a quota is a LIMIT on the quantity or value that can be imported — different tools entirely."}'::jsonb),
('business:6-3-globalisation:misc:c53255ec', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When the pound strengthens, UK exports become cheaper and more competitive abroad.</p><p><strong>✅ The correct idea:</strong> When the pound STRENGTHENS, exports become MORE EXPENSIVE (dearer) for foreign buyers — reducing competitiveness. Use SPICED: Strong Pound → Imports Cheaper, Exports Dearer. A WEAK pound makes exports cheaper.</p>", "question": "What actually happens to UK exports when the pound strengthens?", "options": ["Exports become more expensive and less competitive abroad", "Exports become cheaper and more competitive abroad instantly", "Exports are completely unaffected by any change in the exchange rate", "Exports automatically double in price whenever the pound strengthens"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that a strong pound helps exports — SPICED shows a strong pound makes exports DEARER, reducing competitiveness abroad."}'::jsonb),
('business:6-3-globalisation:misc:e25a6e51', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Globalisation only benefits businesses — host countries always lose out.</p><p><strong>✅ The correct idea:</strong> Globalisation brings mixed effects to host countries. Benefits include jobs, tax revenue, and access to cheaper goods. Drawbacks include profit repatriation, local business closures, and potential exploitation of lower standards.</p>", "question": "Does globalisation only benefit businesses, with host countries always losing out?", "options": ["Yes — host countries never gain any benefit at all from globalisation", "No — host countries gain jobs and tax revenue, but also face some drawbacks", "Yes — but only multinational businesses ever lose out from globalisation", "No — but only because globalisation never actually affects host countries"]}'::jsonb, '{"answer": 1, "explain": "The card explains globalisation brings mixed effects to host countries — benefits like jobs and tax revenue, alongside drawbacks like profit repatriation."}'::jsonb),
('business:6-3-globalisation:misc:9634ef84', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> International branding simply means advertising your product abroad.</p><p><strong>✅ The correct idea:</strong> International branding involves creating a consistent brand identity (image, values, logo) that is recognised across multiple countries, taking into account cultural, religious, language, and legal differences in each market.</p>", "question": "Does international branding simply mean advertising your product abroad?", "options": ["Yes — international branding and advertising abroad are exactly the same thing", "Yes — but only if the advertising uses the exact same language everywhere", "No — it means creating a consistent brand identity recognised across countries", "No — but only because branding never involves any advertising at all"]}'::jsonb, '{"answer": 2, "explain": "The card explains international branding involves creating a consistent identity across countries, considering cultural, religious, language and legal differences."}'::jsonb),
('business:6-3-globalisation:misc:c1058896', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A weaker pound always benefits UK businesses by making everything cheaper.</p><p><strong>✅ The correct idea:</strong> A weaker pound makes UK EXPORTS cheaper for overseas buyers (good for exporters) but makes IMPORTS more expensive for UK businesses (bad for importers). The effect depends on whether the business mainly exports or imports.</p>", "question": "Does a weaker pound always benefit UK businesses by making everything cheaper?", "options": ["Yes — a weaker pound always benefits every single UK business equally", "Yes — but only because a weaker pound has no effect on imports at all", "No — but only because a weaker pound never actually affects exporters", "No — it helps exporters but makes imports more expensive for importers"]}'::jsonb, '{"answer": 3, "explain": "The card explains a weaker pound makes exports cheaper (good for exporters) but makes imports more expensive (bad for importers) — the effect depends on the business."}'::jsonb),
('business:6-3-globalisation:misc:fcae1829', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Businesses should always move production abroad because it is always cheaper.</p><p><strong>✅ The correct idea:</strong> Moving abroad reduces labour costs but brings drawbacks: quality control difficulties, communication problems due to language and time zones, rising foreign wages, and consumer preference for ''Made in Britain''. The decision must weigh up all factors.</p>", "question": "Should businesses always move production abroad because it is always cheaper?", "options": ["No — moving abroad brings drawbacks like quality control and communication issues", "Yes — moving production abroad is always cheaper with absolutely no drawbacks", "Yes — but only because quality control is always easier when producing abroad", "No — but only because foreign wages are always higher than UK wages"]}'::jsonb, '{"answer": 0, "explain": "The card explains moving abroad reduces labour costs but brings drawbacks like quality control, communication problems, rising foreign wages, and consumer preference."}'::jsonb),
('business:6-3-globalisation:misc:2b00f72b', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Globalisation is only about trade in physical goods between countries.</p><p><strong>✅ The correct idea:</strong> Globalisation involves three key flows: TRADE (goods and services), PEOPLE (migration of workers), and CAPITAL (movement of money and physical assets like machines and buildings). It is far broader than just importing and exporting goods.</p>", "question": "Is globalisation only about trade in physical goods between countries?", "options": ["Yes — globalisation only ever involves the trade of physical goods", "No — it also involves the movement of people and capital, not just goods", "Yes — but only capital movement counts as part of globalisation too", "No — but only because physical goods are never traded internationally"]}'::jsonb, '{"answer": 1, "explain": "The card explains globalisation involves three flows — trade, people, and capital — and is far broader than just importing and exporting physical goods."}'::jsonb),
('business:6-3-globalisation:misc:3335b507', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Think global, act local'' means selling the same product at the same price everywhere.</p><p><strong>✅ The correct idea:</strong> ''Think global, act local'' means maintaining the same core brand VALUES worldwide, but adapting the product, price, promotion, and sometimes even the name to suit local cultures, incomes, religions, and legal requirements in each country.</p>", "question": "Does ''think global, act local'' mean selling the same product at the same price everywhere?", "options": ["Yes — the product and price must be kept identical in every single country", "Yes — but only the price needs to stay the same in every single country", "No — it means keeping core brand values, while adapting locally to each market", "No — but only because branding never needs to adapt to different countries"]}'::jsonb, '{"answer": 2, "explain": "The card explains ''think global, act local'' means maintaining core brand values worldwide while adapting product, price and promotion to local cultures and incomes."}'::jsonb),
('business:6-3-globalisation:tips:08f8495b', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1–2 marks — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation, no examples, no paragraphs. For a 2-mark <strong>''Explain''</strong> question, add one sentence explaining <em>why</em> — nothing more.</p>\n\n      <p><strong>The Formula (1 mark):</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general point = 0 marks ❌</li>\n      </ul>\n\n      <p><strong>The Formula (2 marks):</strong></p>\n      <ul>\n        <li>Make a point (1) + Explain how it works (1)</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Identify a reason why a UK business might locate in another country\" (0 marks):</strong><br/>\n      <em>\"More customers.\"</em><br/>\n      This is a marketing answer, not a location answer. You can gain more customers without moving abroad.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Lower labour costs in the host country.\"</em><br/>\n      This is specific to location — it explains WHY a business would physically move operations.</p>\n\n      <p><strong>❌ Bad Answer — \"Explain one advantage of operating as a multinational\" (0 marks):</strong><br/>\n      <em>\"A multinational can sell to more people and make more money.\"</em><br/>\n      Any business can sell abroad without being a multinational. This doesn''t explain what''s special about operating in multiple countries.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"A multinational can spread its risk across different markets (1). This means that if consumer spending falls in one country, the business can rely on income from other countries to protect overall profits (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, many students lost marks on the ''identify two factors that led to increased globalisation'' question by listing the same factor twice in different words (e.g., \"the internet\" and \"e-commerce\" and \"online banking\" — these are all the same thing and count as one answer). Make sure your two factors are genuinely different.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a paragraph about everything you know about globalisation when asked to simply identify a factor. You will waste time and score the same mark as someone who wrote two words.</p>\n    ", "question": "According to this card, what mistake did many students make on the ''identify two factors'' question?", "options": ["They gave a factor that was completely unrelated to globalisation entirely", "They wrote far too little detail for a question that was actually worth two whole marks", "They forgot to identify any factor relating to globalisation at all", "They listed the same factor twice using different words, such as internet and e-commerce"]}'::jsonb, '{"answer": 3, "explain": "The card warns students lost marks by listing the same factor twice in different words, like ''the internet'' and ''e-commerce'' — the two factors must be genuinely different."}'::jsonb),
('business:6-3-globalisation:tips:4cca4fb1', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Calculate — 1 mark — Show Your Working. Every Single Time.", "reading": "\n      <p>Calculation questions in globalisation topics are usually straightforward — but students regularly drop marks by not showing their working. Even if your final answer is wrong, you can still earn the mark if your method is correct.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>Write the calculation clearly: e.g., <strong>500,000 × 80/100</strong></li>\n        <li>Write the final answer with the correct unit: e.g., <strong>400,000 tyres</strong></li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"400,000\"</em><br/>\n      No working shown. If the examiner can''t see your method, they can''t award a method mark.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>500,000 × 80/100 = <strong>400,000 tyres</strong></em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> For percentage questions, always convert the percentage properly. 80% means 80 divided by 100 — not 80 divided by 10. A common mistake is dividing by the wrong number.</p>\n\n      <p><strong>💡 Tip:</strong> Always include the unit in your answer (e.g., \"tyres\", \"£\", \"%\"). Examiners appreciate precision and it shows you understood the question.</p>\n    ", "question": "According to this card, why is it important to show your working in a calculation question?", "options": ["You can still earn the mark for a correct method even if the final answer is wrong", "Showing your working automatically doubles the marks available for the question", "The examiner only ever looks at the final numerical answer given, not the method", "Working is only required for calculations involving percentages, not other sums"]}'::jsonb, '{"answer": 0, "explain": "The card explains that showing your working lets you earn a method mark even if the final answer is wrong — no working shown means no method mark is available."}'::jsonb),
('business:6-3-globalisation:tips:493ed558', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks (per point) — The Holy Trinity: U → APP → AN", "reading": "\n      <p>Every single 3-mark analyse question in Business Studies follows the same pattern. Master this structure and you will pick up marks consistently across the whole exam.</p>\n\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — U (Understanding):</strong> State the advantage, disadvantage, or impact using business terminology.</li>\n        <li><strong>Step 2 — APP (Application):</strong> Quote or refer directly to the specific business in the case study. Use their name, a figure, or a detail from the text.</li>\n        <li><strong>Step 3 — AN (Analysis):</strong> State the financial or operational consequence for the business. Think: costs, revenue, profit, efficiency, market share, share price, dividends.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Analyse an advantage of AZ operating as a multinational\" (1 mark max):</strong><br/>\n      <em>\"AZ can make more money because it sells to more people.\"</em><br/>\n      This is vague, has no case study detail, and any business can sell to more people without being a multinational.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"One advantage is that AZ is able to access a larger pool of skilled workers in different countries (U). AZ has approximately 75,000 employees worldwide across its three research and development centres (APP). This means AZ can attract the best scientific talent globally, leading to more innovative treatments and higher profits in the long run (AN).\"</em></p>\n\n      <p><strong>🚫 Critical Warning — Being a Multinational ≠ Just Selling Abroad:</strong><br/>\n      The examiner''s report on this paper specifically stated: <em>\"Being a multinational is more than just being able to sell abroad. Any business can sell to more countries without being a multinational.\"</em> What makes an MNC special is that it physically OPERATES in multiple countries — so your advantages must reflect this: lower costs in host countries, access to local labour, spreading risk, dealing with different tax regimes.</p>\n\n      <p><strong>💡 The \"So What?\" Rule for Analysis:</strong><br/>\n      Keep asking yourself \"So what?\" until you hit a bottom-line business impact.</p>\n      <ul>\n        <li>\"AZ operates in over 100 countries.\" → So what?</li>\n        <li>\"They can sell more medicines.\" → So what?</li>\n        <li>\"This increases total revenue and allows AZ to reinvest profits into developing new treatments.\" ✅ <strong>This is AN.</strong></li>\n      </ul>\n\n      <p><strong>Sentence Starters to Use:</strong></p>\n      <ul>\n        <li><strong>APP:</strong> \"Because the text states that AZ operates in over 100 countries...\" / \"In the case of AZ, with 75,000 employees worldwide...\"</li>\n        <li><strong>AN:</strong> \"This will lead to...\" / \"As a result, the business will...\" / \"This reduces costs, meaning profit margins improve...\"</li>\n      </ul>\n    ", "question": "According to this card, what makes a multinational company special, beyond just selling abroad?", "options": ["It refuses to sell any of its products in its own home country at all", "It physically operates in multiple countries, such as through lower costs and access to labour", "It only ever sells its products in one single foreign country outside its own home market entirely", "It is legally prevented from paying any tax in any country it operates in"]}'::jsonb, '{"answer": 1, "explain": "The card''s examiner warning states being a multinational means physically OPERATING in multiple countries — not just being able to sell abroad like any business."}'::jsonb),
('business:6-3-globalisation:tips:f3f933e5', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Impacts — 6 marks — Just Do the 3-Mark Formula Twice", "reading": "\n      <p>A 6-mark ''Analyse two impacts'' question is simply a <strong>3-mark question done twice</strong>. There are no evaluation marks here — do not write a conclusion or recommendation. You will score zero for it and waste precious time.</p>\n\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1:</strong> U → APP → AN (3 marks)</li>\n        <li><strong>Impact 2:</strong> U → APP → AN (3 marks)</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Analyse two benefits to Virgin Atlantic of developing an international brand\" (2 marks max):</strong><br/>\n      <em>\"International branding helps Virgin Atlantic get more customers and make more money. It also means people trust the brand more.\"</em><br/>\n      There is no case study detail and no clear business-facing consequence. This scores at most 1 mark per impact.</p>\n\n      <p><strong>✅ Good Answer — Impact 1 (3 marks):</strong><br/>\n      <em>\"International branding creates a consistent message that is recognised across many markets (U). Virgin Atlantic flies to destinations around the world and has pursued growth and international branding since its launch in 1984 (APP). This means that customers globally associate Virgin with quality service, leading to more flight bookings and higher revenue for the business (AN).\"</em></p>\n\n      <p><strong>✅ Good Answer — Impact 2 (3 marks):</strong><br/>\n      <em>\"An international brand can reduce the marketing costs of operating globally (U). Because Virgin Atlantic already has a globally recognised brand identity, it can use the same advertising campaigns across all the countries it flies to (APP). This avoids the need to develop separate campaigns for each market, reducing overall costs and improving profit margins (AN).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The most common mistake in 6-mark questions is repeating the same impact twice with slightly different words (e.g., ''more sales'' and ''more customers'' — this is the same point). Make sure your two impacts are genuinely different.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT spend half your answer defining what international branding is. The examiner already knows. Use that time to apply it to the specific business and analyse the impact.</p>\n\n      <p><strong>💡 Tip — Impacts can be negative too:</strong> For questions like \"Analyse two impacts of globalisation on JLR\", you can use one positive and one negative impact. This shows balanced thinking and is perfectly acceptable.</p>\n    ", "question": "According to this card, should a 6-mark ''analyse two impacts'' answer include a conclusion?", "options": ["Yes — a strong conclusion is worth one of the six marks that are available", "Yes — without a conclusion the answer cannot be marked by the examiner at all", "No — there are no evaluation marks, so a conclusion wastes time and scores zero", "No — but only because the question does not require two separate impacts"]}'::jsonb, '{"answer": 2, "explain": "The card warns there are no evaluation marks in a 6-mark question — writing a conclusion wastes time and scores zero, since it is simply the 3-mark formula done twice."}'::jsonb),
('business:6-3-globalisation:tips:a4f75291', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "State What is Meant By — 2 marks — Define the Term Precisely — Not Vaguely", "reading": "\n      <p>A 2-mark ''State what is meant by'' question wants a <strong>clear, complete definition</strong>. It must include both key parts of the concept — not just one half of it.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Part 1 (1 mark):</strong> The core idea or feature of the term.</li>\n        <li><strong>Part 2 (1 mark):</strong> The full scope — e.g., where it happens, who it involves, what it leads to.</li>\n      </ul>\n\n      <p><strong>The Classic Trap — International Branding:</strong><br/>\n      The examiner''s report on this paper stated this was <em>\"not well understood by most candidates\"</em> and was frequently confused with being a multinational or international trade. These are <strong>completely different concepts</strong>:</p>\n      <ul>\n        <li><strong>International branding</strong> = creating a recognisable image/identity for a product that is promoted consistently across multiple countries.</li>\n        <li><strong>International trade</strong> = buying and selling goods between countries.</li>\n        <li><strong>Multinational</strong> = a business that operates (has facilities) in more than one country.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"State what is meant by international branding\" (0 marks):</strong><br/>\n      <em>\"When a company sells its products all over the world.\"</em><br/>\n      This is a definition of international trade, not international branding. No marks.</p>\n\n      <p><strong>❌ Partial Answer (1 mark only):</strong><br/>\n      <em>\"When a business creates a brand for its product.\"</em><br/>\n      This only defines ''branding'' — there is nothing ''international'' about it.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"International branding is when a business creates a recognisable image or identity for its product (1) that is then promoted and recognised consistently in countries all around the world (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> This term has a very specific meaning. The examiner will not reward an answer that talks about selling abroad, being a multinational, or expanding internationally — unless it specifically mentions creating a consistent brand image across countries.</p>\n    ", "question": "According to this card, why did ''international branding'' catch out most candidates?", "options": ["It was never actually tested in any real past exam paper at all", "It only ever appears in nine-mark evaluate questions, never anywhere else", "It requires a detailed calculation rather than a written definition", "It was frequently confused with being a multinational or international trade"]}'::jsonb, '{"answer": 3, "explain": "The card cites the examiner''s report stating international branding was ''not well understood'' and frequently confused with being a multinational or international trade."}'::jsonb),
('business:6-3-globalisation:tips:639b12dd', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — APP + AN First, Then Make a Judgement That Uses the Case Study", "reading": "\n      <p>A 7-mark evaluate question has three layers of marks: Application (2), Analysis (2), and Evaluation (3). Most students pick up the first four marks without too much difficulty — it''s the <strong>3 evaluation marks</strong> where marks are lost.</p>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — APP + AN:</strong> Benefit/impact 1, linked to the business with a financial consequence.</li>\n        <li><strong>Paragraph 2 — APP + AN:</strong> Benefit/impact 2, linked to the business with a different financial consequence.</li>\n        <li><strong>Paragraph 3 — EVAL (Start):</strong> A clear judgement — state your overall view.</li>\n        <li><strong>Paragraph 4 — EVAL (Develop):</strong> Justify and contextualise — reference the case study evidence to support your judgement. Use \"it depends on...\" or weigh one factor against another.</li>\n      </ul>\n\n      <p><strong>❌ Bad Evaluation (1 mark max):</strong><br/>\n      <em>\"Overall, international branding is very important for Unilever.\"</em><br/>\n      This is a basic decision with no justification. It scores 1 mark at best.</p>\n\n      <p><strong>✅ Good Evaluation (3 marks):</strong><br/>\n      <em>\"Overall, international branding is the most important factor in Unilever''s growth (EVAL) because it allows a consistent campaign to run across all 190 countries they operate in, saving on marketing costs through economies of scale (EVAL). However, the value of this depends on the economic climate — if consumer incomes fall globally, even well-known brands like Persil and Dove may see declining sales as customers switch to cheaper alternatives (EVAL).\"</em></p>\n\n      <p><strong>💡 The \"It Depends On...\" Rule:</strong><br/>\n      The very best evaluation answers don''t just say \"X is important.\" They say: <em>\"X is the most important factor, BUT it depends on [a specific contextual condition].\"</em></p>\n      <ul>\n        <li>\"Globalisation is essential for BP''s location decisions, but it depends on whether the global oil price remains high enough to justify the cost of operating rigs in Norway and Angola.\"</li>\n        <li>\"International branding is vital for Unilever, but its impact depends on whether the difficult economic climate suppresses consumer spending worldwide.\"</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, the examiner noted that many evaluation answers simply repeated analysis from earlier paragraphs. <em>Repeating analysis is NOT evaluation.</em> Evaluation must add something new — a judgement, a condition, a weighing of factors.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT open a 7-mark evaluate question with a long definition of globalisation or international branding. There are <strong>zero knowledge marks</strong> in a pure evaluate question. Go straight to APP and AN.</p>\n\n      <p><strong>Sentence Starters for Evaluation:</strong></p>\n      <ul>\n        <li>\"Overall, I believe that... because...\"</li>\n        <li>\"The most significant factor is... because it directly affects...\"</li>\n        <li>\"However, this depends entirely on whether...\"</li>\n        <li>\"In the context of [business name], this is particularly important because...\"</li>\n      </ul>\n    ", "question": "According to this card, why does simply repeating earlier analysis not count as evaluation?", "options": ["Evaluation must add something new — a judgement, condition, or weighing of factors", "Repeating analysis is actually the correct way to score all three evaluation marks", "Evaluation marks are awarded automatically regardless of what is actually written", "There are no evaluation marks available at all in a seven-mark question"]}'::jsonb, '{"answer": 0, "explain": "The card warns repeating analysis is NOT evaluation — evaluation must add something new, such as a judgement, a condition, or weighing factors against each other."}'::jsonb),
('business:6-3-globalisation:tips:a8378495', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — Knowledge + Balanced Analysis + A Contextual Verdict", "reading": "\n      <p>A 9-mark evaluate question is the most demanding question type. It tests all five assessment objectives: K, U, APP, AN, and EVAL. You must cover <strong>both sides</strong> (risk AND reward, or advantage AND disadvantage) and reach a clear, justified verdict that uses the case study.</p>\n\n      <p><strong>The Mark Split to Remember:</strong></p>\n      <ul>\n        <li>Knowledge (1) + Understanding (1) + Application (2) + Analysis (2) + Evaluation (3) = 9</li>\n      </ul>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K + U:</strong> Define the key concept (e.g., globalisation) and explain what it involves. Keep this brief — 2 sentences maximum.</li>\n        <li><strong>Paragraph 2 — APP + AN (Reward/Advantage):</strong> One clear benefit, linked to the business, with a financial/operational consequence for shareholders.</li>\n        <li><strong>Paragraph 3 — APP + AN (Risk/Disadvantage):</strong> One clear risk, linked to the business, with a financial/operational consequence for shareholders.</li>\n        <li><strong>Paragraph 4 — EVAL × 3:</strong> A clear overall judgement, justified with case study context, and a condition that could change your verdict.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (3 marks max):</strong><br/>\n      <em>\"Globalisation is when businesses operate around the world. Aston Martin can sell to more countries, which means more profit. But it also faces more competition. Overall globalisation is good for Aston Martin.\"</em><br/>\n      No case study detail, no financial consequences, and the evaluation is just a basic statement.</p>\n\n      <p><strong>✅ Good Answer — Paragraph structure (approaching full marks):</strong></p>\n      <ul>\n        <li><strong>K+U:</strong> \"Globalisation is the process of interaction and integration between businesses, governments and people worldwide. It involves the increasing movement of goods, capital and labour across national borders.\"</li>\n        <li><strong>APP+AN (Reward):</strong> \"One reward for AM plc''s shareholders is that globalisation has allowed AM plc to open 150 dealerships in over 50 countries across six continents (APP). With a larger global customer base, revenue from car sales can increase significantly, leading to higher profits and potentially higher dividends paid to shareholders (AN).\"</li>\n        <li><strong>APP+AN (Risk):</strong> \"However, globalisation also creates risk. AM plc relies on a globalised supply chain with suppliers from the UK, EU and across the world (APP). If a supplier in another country experiences disruption — for example due to political instability or exchange rate fluctuations — production could be delayed, increasing costs and reducing profit margins, which would lower the dividends shareholders receive (AN).\"</li>\n        <li><strong>EVAL:</strong> \"Overall, the rewards of globalisation are likely to outweigh the risks for AM plc''s shareholders (EVAL), because the global demand for luxury sports cars is growing and AM plc''s strong brand identity across 50+ countries gives it a competitive advantage in premium markets (EVAL). However, this depends on whether exchange rate movements make AM plc''s cars more expensive abroad — if sterling strengthens, exports become pricier and international sales could fall, directly reducing shareholder dividends (EVAL).\"</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Always link analysis to the <strong>shareholders specifically</strong> — not just ''the business''. Shareholders care about: dividends, share price, return on investment, and financial risk. Make sure your consequences reference at least one of these.</p>\n\n      <p><strong>💡 The Contextual Evaluation Rule:</strong> To earn all 3 evaluation marks, your judgement must reference specific detail from the case study. A general statement like \"globalisation is mostly beneficial\" only scores 1 mark. A contextual verdict using the bar charts, specific figures, or named products earns all 3.</p>\n    ", "question": "According to this card, who must the analysis in a 9-mark question specifically link to?", "options": ["Competitors specifically, referencing their exact market share percentage figures", "Shareholders specifically, referencing dividends, share price or investment return", "Suppliers specifically, referencing only the length of their payment terms", "The general public, with no reference at all to any particular stakeholder"]}'::jsonb, '{"answer": 1, "explain": "The card''s examiner warning states analysis must link to shareholders specifically — dividends, share price, return on investment, and financial risk."}'::jsonb),
('business:6-3-globalisation:tips:b79585ae', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Judgement First, Then Justify Using the Case Study", "reading": "\n      <p>A 3-mark ''Recommend'' question follows a clear pattern: <strong>make a decision, justify it, and use the case study</strong>. These marks are very accessible if you stick to the structure — but many students lose 2 out of 3 by giving a vague, unsupported recommendation.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>1 mark:</strong> A clear recommendation (yes/no, continue/stop, option A/B).</li>\n        <li><strong>+ 1 mark:</strong> A reason WHY — with no case study detail needed.</li>\n        <li><strong>+ 1 mark (or replaces above):</strong> A contextual justification — use a specific fact, figure, or detail from the case study.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer — \"Recommend whether AZ should continue to operate as a multinational\" (1 mark):</strong><br/>\n      <em>\"Yes, AZ should continue as a multinational because it is a good idea.\"</em><br/>\n      There is no justification and no case study detail.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"AZ should continue to operate as a multinational (1). Without global operations, AZ would be unable to generate the profits needed to fund its research (1). This is particularly important as AZ has three research and development centres and 10,000 staff working to develop new treatments — all of which require significant ongoing investment (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> On this paper, the examiner noted that most candidates correctly said AZ should continue as a multinational, but many failed to justify it with case study context. Always find at least one specific detail from the text to support your recommendation.</p>\n\n      <p><strong>💡 Tip — You don''t always have to recommend \"yes\":</strong> If there is a strong case for the opposite view, argue it — as long as you can justify it with context. Examiners award marks for the quality of justification, not for picking the \"right\" side.</p>\n\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li>\"[Business] should [recommendation] because...\"</li>\n        <li>\"Without this, [business] would be unable to...\"</li>\n        <li>\"This is supported by the fact that the case study states...\"</li>\n      </ul>\n    ", "question": "According to this card, why do many students lose 2 out of 3 marks on recommend questions?", "options": ["They recommend an option that is not mentioned anywhere in the question", "They spend too much time defining every key term before making a decision", "They give a vague recommendation without any case study justification", "They give two separate recommendations instead of committing to just one"]}'::jsonb, '{"answer": 2, "explain": "The card explains most candidates give a vague recommendation without case study context, losing marks despite correctly identifying the right answer."}'::jsonb),
('business:6-3-globalisation:tips:216347e1', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "MCQ — 1 mark — Eliminate First. Don''t Rush. Watch the ''NOT'' Questions.", "reading": "\n      <p>Multiple choice questions on globalisation are worth just 1 mark each — but students regularly drop them through careless reading. The most dangerous word in an MCQ is <strong>NOT</strong>.</p>\n\n      <p><strong>The Strategy:</strong></p>\n      <ul>\n        <li><strong>Step 1:</strong> Read the question stem carefully. Underline key words like \"NOT\", \"most likely\", \"best describes\".</li>\n        <li><strong>Step 2:</strong> Eliminate the options you''re certain are wrong.</li>\n        <li><strong>Step 3:</strong> Choose from what remains — don''t second-guess yourself.</li>\n      </ul>\n\n      <p><strong>⚠️ The \"NOT\" Trap:</strong><br/>\n      Q1 on this paper asked: <em>\"What has NOT contributed to increased globalisation?\"</em><br/>\n      Many students chose options A, B or D because they are true statements about globalisation — but the question asked for what has NOT contributed. The answer is C (trade restrictions) because restrictions <em>block</em> globalisation.</p>\n\n      <p><strong>⚠️ The Terminology Trap:</strong><br/>\n      Questions on this paper tested whether students could distinguish between very similar terms:</p>\n      <ul>\n        <li><strong>Globalisation</strong> = the interconnected nature of business activities across the world.</li>\n        <li><strong>International branding</strong> = creating a consistent brand image across countries — requires taking account of <em>cultural differences</em>.</li>\n        <li><strong>Multinational organisation</strong> = a business that <em>operates</em> in several countries.</li>\n      </ul>\n\n      <p><strong>❌ Common MCQ Mistake:</strong><br/>\n      Confusing ''international branding'' (requires cultural awareness — Answer D) with ''selling goods in every country'' (Answer C). A brand can be international without selling everywhere — but it always requires sensitivity to local culture.</p>\n\n      <p><strong>💡 Final Tip:</strong> If you are unsure between two answers, re-read the question one more time and pick the answer that most precisely matches the exact wording. Never leave an MCQ blank — there is no negative marking.</p>\n    ", "question": "According to this card, why is the word ''NOT'' so dangerous in an MCQ question stem?", "options": ["The word ''NOT'' automatically makes every single answer option in the question incorrect", "Questions containing the word ''NOT'' are always worth double the normal marks", "The word ''NOT'' means the question has no correct answer among the options given", "Students may pick a true statement about the topic instead of answering what was NOT asked"]}'::jsonb, '{"answer": 3, "explain": "The card''s example shows students chose true statements about globalisation instead of correctly identifying the option that had NOT contributed to it."}'::jsonb),
('business:6-3-globalisation:tips:216f46e2', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tips', 'mcq', 1, '{"readingTitle": "Common Misconceptions — All Question Types — The Four Concepts Students Constantly Confuse", "reading": "\n      <p>The examiner''s report on this paper explicitly stated that students regularly confused four key globalisation concepts. <strong>These are not the same thing.</strong> Using one term when you mean another will cost you marks across every question type.</p>\n\n      <p><strong>The Four Concepts — Know the Difference:</strong></p>\n      <ul>\n        <li><strong>Globalisation:</strong> The process by which businesses, governments, and people become increasingly interconnected and interdependent across the world. It is driven by improvements in technology, transport, and trade agreements.</li>\n\n        <li><strong>International Trade:</strong> The buying and selling of goods and services between countries. A small local business can participate in international trade without being a multinational or having an international brand.</li>\n\n        <li><strong>International Branding:</strong> Creating a consistent image, logo, or identity for a product that is recognised and promoted across multiple countries. It requires taking account of cultural and religious differences in each market.</li>\n\n        <li><strong>Multinational Company (MNC):</strong> A business that physically OPERATES in more than one country — not just sells there. This means having factories, offices, staff, or facilities in other countries.</li>\n      </ul>\n\n      <p><strong>❌ Classic Confusion (costs marks in EVERY question):</strong><br/>\n      <em>\"Unilever is an international brand because it sells products in 190 countries.\"</em><br/>\n      Selling in 190 countries makes Unilever a multinational. The international BRAND part is about the consistent logo/image (Dove, Lynx, Persil) that is recognised in those countries.</p>\n\n      <p><strong>✅ Correct Distinction:</strong><br/>\n      <em>\"Unilever is a multinational company that uses international branding — products like Persil and Dove have a consistent image that is recognised worldwide, helping build customer loyalty across all 190 markets.\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The examiner''s report on this paper specifically said: <em>\"International branding, international trade, international marketing, and multinational companies are not inter-changeable terms. This confusion has been seen from many candidates. Centres need to ensure that these are understood as clearly separate concepts.\"</em></p>\n\n      <p><strong>💡 Quick Test — Can You Answer These?</strong></p>\n      <ul>\n        <li>Can a business trade internationally without being a multinational? <strong>YES</strong> — it just sells abroad.</li>\n        <li>Can a multinational exist without an international brand? <strong>YES</strong> — it could operate different brands in different countries.</li>\n        <li>Does international branding require selling in every country? <strong>NO</strong> — just a consistent brand across the countries where it does operate.</li>\n      </ul>\n    ", "question": "According to this card, what is the classic confusion the examiner''s report warned about?", "options": ["Calling Unilever an ''international brand'' simply because it sells in 190 countries", "Calling Unilever a ''multinational'' simply because it has a recognised brand image", "Calling Unilever an ''exporter'' simply because it operates factories abroad", "Calling Unilever a ''host country'' simply because it sells in many countries"]}'::jsonb, '{"answer": 0, "explain": "The card explains selling in 190 countries makes Unilever a multinational — the international BRAND is specifically about the consistent logo/image recognised there."}'::jsonb),
